/**
 * The estimated order fee.
 * @export
 * @interface SimpleOrderPreviewEstimatedFee
 */
export interface SimpleOrderPreviewEstimatedFee {
    [key: string]: any;
    /**
     * Symbol to identify a cryptocurrency or fiat currency on a crypto exchange. Fiat currencies symbols are ISO-4217 codes.
     * @type {string}
     * @memberof SimpleOrderPreviewEstimatedFee
     */
    'currency': string;
    /**
     *
     * @type {string}
     * @memberof SimpleOrderPreviewEstimatedFee
     */
    'amount': string;
}
